import{_ as s,o as e,c as n,a2 as p}from"./chunks/framework.BWuWLRhz.js";const m=JSON.parse('{"title":"CLI","description":"","frontmatter":{},"headers":[],"relativePath":"zh/reference/cli.md","filePath":"zh/reference/cli.md","lastUpdated":1783819766000}'),i={name:"zh/reference/cli.md"};function t(l,a,o,c,d,r){return e(),n("div",null,[...a[0]||(a[0]=[p(`<h1 id="cli" tabindex="-1">CLI <a class="header-anchor" href="#cli" aria-label="Permalink to &quot;CLI&quot;">​</a></h1><p>包内自带零依赖命令行工具（纯 stdlib——无 docker、无服务进程），在 shell 里直接查看一个 store：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wikimem</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --store</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./memory</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">comman</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 或者：python -m wikimem</span></span></code></pre></div><p><code>--store</code> / <code>-s</code> 默认读 <code>WIKIMEM_STORE</code> 环境变量，其次是当前目录。</p><p>退出码遵循 shell 惯例：<code>0</code> 成功，<code>1</code> 无匹配 / 不存在，<code>2</code> 用法或 store 错误。</p><h2 id="ls" tabindex="-1"><code>ls</code> <a class="header-anchor" href="#ls" aria-label="Permalink to &quot;\`ls\`&quot;">​</a></h2><p>列出 categories 与条目数：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ wikimem -s ./memory ls</span></span>
<span class="line"><span>daily_life      1</span></span>
<span class="line"><span>preferences     2</span></span></code></pre></div><h2 id="show-category-name" tabindex="-1"><code>show &lt;category&gt; [name]</code> <a class="header-anchor" href="#show-category-name" aria-label="Permalink to &quot;\`show &lt;category&gt; [name]\`&quot;">​</a></h2><p>按文件存储的原样打印一个 category（或单个条目）——标题、内容、溯源注释：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ wikimem -s ./memory show preferences likes-the-sea</span></span>
<span class="line"><span>## likes-the-sea</span></span>
<span class="line"><span></span></span>
<span class="line"><span>喜欢海边，提到过想去海边玩。[[daily_life:beach-trip-plan]]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;!-- wikimem: owner=user:xnne | ts=2026-07-10T03:00:00+00:00 --&gt;</span></span></code></pre></div><h2 id="grep-pattern-i" tabindex="-1"><code>grep &lt;pattern&gt; [-i]</code> <a class="header-anchor" href="#grep-pattern-i" aria-label="Permalink to &quot;\`grep &lt;pattern&gt; [-i]\`&quot;">​</a></h2><p>对条目名与内容做正则搜索，输出带 <code>category:name</code> 前缀（grep 风格）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ wikimem -s ./memory grep 海边</span></span>
<span class="line"><span>preferences:likes-the-sea:喜欢海边，提到过想去海边玩。[[daily_life:beach-trip-plan]]</span></span>
<span class="line"><span>daily_life:beach-trip-plan:计划夏天去海边旅行，看日出。</span></span></code></pre></div><h2 id="explain-query" tabindex="-1"><code>explain &quot;&lt;query&gt;&quot;</code> <a class="header-anchor" href="#explain-query" aria-label="Permalink to &quot;\`explain &quot;&lt;query&gt;&quot;\`&quot;">​</a></h2><p>跑一次真实检索（<code>MemoryIndex.retrieve(..., explain=True)</code>）并打印打分明细：命中排序、一跳 wiki-link 展开及其来源、token 估算、预算裁剪、悬空链接。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ wikimem -s ./memory explain &quot;想去海边玩&quot;</span></span>
<span class="line"><span>query: 想去海边玩</span></span>
<span class="line"><span>query tokens: 想去, 去海, 海边, 边玩</span></span>
<span class="line"><span>ranking: BM25 (embedding: off)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  #  src      score     bm25    cos  ~tok  item</span></span>
<span class="line"><span>  1  hit     1.676    1.676      -     22  preferences:likes-the-sea  [去海, 海边, ...]</span></span>
<span class="line"><span>  2  link        -        -      -     15  daily_life:beach-trip-plan  (via likes-the-sea)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>budget: used 37 / no limit</span></span>
<span class="line"><span>unresolved links: [[missing:gone]]</span></span></code></pre></div><p>参数：<code>--limit N</code>（命中上限，默认 10）、<code>--budget N</code>（token 预算——被裁掉的条目会列出）、<code>--no-links</code>（关闭一跳展开）、<code>--jieba</code> / <code>--no-jieba</code>（强制 CJK 分词路径，默认自动）。</p><p>CLI 始终走 BM25 路径——embedding 融合需要配置端点，属于宿主配置，不属于 shell 查看场景。</p><h2 id="graph-format-mermaid-json" tabindex="-1"><code>graph [--format mermaid|json]</code> <a class="header-anchor" href="#graph-format-mermaid-json" aria-label="Permalink to &quot;\`graph [--format mermaid|json]\`&quot;">​</a></h2><p>从 markdown 中解析 <code>[[category:item]]</code>，导出 wiki-link 关系图。这就是 Neo4j 语义层可视化退役后的接替者：零基础设施，同一张图。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ wikimem -s ./memory graph</span></span>
<span class="line"><span>graph LR</span></span>
<span class="line"><span>    n0[&quot;daily_life:beach-trip-plan&quot;]</span></span>
<span class="line"><span>    n1[&quot;preferences:likes-the-sea&quot;]</span></span>
<span class="line"><span>    n2[&quot;missing:gone&quot;]:::unresolved</span></span>
<span class="line"><span>    n1 --&gt; n0</span></span>
<span class="line"><span>    n1 --&gt; n2</span></span>
<span class="line"><span>    classDef unresolved stroke-dasharray: 5 5;</span></span></code></pre></div><p>mermaid 输出可直接粘进任何 markdown 渲染器。store 中不存在的链接目标会保留为虚线 <code>unresolved</code> 节点，悬空引用一眼可见。</p><p><code>--format json</code> 输出 <code>{&quot;nodes&quot;: [...], &quot;edges&quot;: [...]}</code>（节点字段：<code>id</code> / <code>category</code> / <code>name</code> / <code>unresolved</code>），宿主前端可自行渲染。</p>`,24)])])}const g=s(i,[["render",t]]);export{m as __pageData,g as default};
